console.log(`⏭️ Następny klient po: ${d.klientNazwa || d.tytul || 'nieznany'}`);
return [{ json: d }];

const sheetResp  = $input.first().json;
const clientMeta = $('⚙️ Przygotuj Klienta4').first().json;

console.log('=== PARSE START ===');
console.log('Klient:', clientMeta.klientNazwa);

if (sheetResp.error || !sheetResp.values) {
  return [{
    json: {
      __noData: true,
      klientNazwa: clientMeta.klientNazwa,
      sheetName: clientMeta.sheetName
    }
  }];
}

const rows = sheetResp.values;

const R = {
  data: 4, tytul: 5, typGrafiki: 6, typPosta: 7,
  linkGrafiki: 10, opis: 12, cta: 14, hasztagi: 16,
  status: 18, notatki: 20, feedback: 22, taskId: 24,
};

function colToLetter(idx) {
  let r = '', n = idx + 1;
  while (n > 0) { n--; r = String.fromCharCode(65 + (n % 26)) + r; n = Math.floor(n / 26); }
  return r;
}

function cell(rowIdx, colIdx) {
  const row = rows[rowIdx];
  if (!row || colIdx >= row.length) return '';
  const val = row[colIdx];
  if (val === null || val === undefined) return '';
  return String(val).trim();
}

/* 🔥 DODANE: ROW 8 i 9 */
function getOpisGrafiki(col) {
  const v = cell(8, col);
  return v || null;
}

function getOpisVideo(col) {
  const v = cell(9, col);
  return v || null;
}

const MO = {
  'stycznia':0,'lutego':1,'marca':2,'kwietnia':3,
  'maja':4,'czerwca':5,'lipca':6,'sierpnia':7,
  'września':8,'października':9,'listopada':10,'grudnia':11
};

function parseDate(str) {
  if (!str) return null;
  const m = String(str).toLowerCase().match(
    /(stycznia|lutego|marca|kwietnia|maja|czerwca|lipca|sierpnia|września|października|listopada|grudnia)\s+(\d{1,2}),?\s+(\d{4})/i
  );
  if (m) {
    const mon = MO[m[1].toLowerCase()];
    if (mon !== undefined) return new Date(Number(m[3]), mon, Number(m[2]));
  }
  return null;
}

const SM = {
  'APPROVED': 'Zatwierdzone przez klienta',
  'WAITING FOR APPROVAL': 'Wyslane do klienta',
  'NEEDS EDITING': 'Poprawki zakonczone',
  'DRAFT': 'Do zrobienia',
  'IN PROGRESS': 'W realizacji',
  'PUBLISHED': 'W realizacji'
};

const PUSTE = new Set(['','brak','none','null','undefined','task_id','task id','-','—','#ref!']);
const czyMaTask = id => id.length > 0 && !PUSTE.has(id.toLowerCase());

const maxCols = Math.max(0, ...rows.map(r => r?.length || 0));
const posts = [];
let currentDate = '', currentDateObj = null;

for (let col = 1; col < maxCols; col++) {

  const dateInCol = cell(R.data, col);
  if (dateInCol) {
    currentDate = dateInCol;
    currentDateObj = parseDate(dateInCol);
  }

  const tytul     = cell(R.tytul, col);
  const opis      = cell(R.opis, col);
  const linkRaw   = cell(R.linkGrafiki, col);
  const typPosta  = cell(R.typPosta, col);
  const typGraf   = cell(R.typGrafiki, col);
  const statusRaw = cell(R.status, col);
  const taskId    = cell(R.taskId, col);

  const realTyp = typPosta && typPosta !== '-';
  const realTytul = tytul && tytul !== '-';
  const realOpis = opis && opis !== '-';
  const realLink = linkRaw && !linkRaw.toLowerCase().includes('link to google');

  if (!realTyp) continue;
  if (!realTytul && !realOpis && !realLink) continue;

  const cta      = cell(R.cta, col);
  const hasztagi = cell(R.hasztagi, col);
  const notatki  = cell(R.notatki, col);
  const feedback = cell(R.feedback, col);

  const cleanLink = realLink ? linkRaw : '';
  const colLetter = colToLetter(col);
  const juzMaTask = czyMaTask(taskId);

  console.log(`  ${colLetter}: "${tytul || opis?.slice(0,40)}" | ${typPosta}`);

  posts.push({
    klientId: clientMeta.klientId,
    klientNazwa: clientMeta.klientNazwa,
    clickupListaId: clientMeta.clickupListaId,
    spreadsheetId: clientMeta.spreadsheetId,
    sheetName: clientMeta.sheetName,

    colIdx: col,
    colLetter,
    writeRange: `${clientMeta.sheetName}!${colLetter}25`,

    dataRaw: currentDate,
    postDateISO: currentDateObj ? currentDateObj.toISOString() : null,
    postDateLabel: currentDateObj
      ? currentDateObj.toLocaleDateString('pl-PL', { weekday:'long', day:'numeric', month:'long', year:'numeric' })
      : currentDate,
    dueTimestamp: currentDateObj ? currentDateObj.getTime() : null,

    tytul,
    typGrafiki: typGraf,
    typPosta,
    linkGrafiki: cleanLink,

    opis,
    cta,
    hasztagi,
    notatki,
    feedback,

    /* 🔥 DODANE POLA */
    OpisGrafiki: getOpisGrafiki(col),
    OpisVideo: getOpisVideo(col),

    statusRaw,
    clickupStatus: SM[statusRaw?.toUpperCase()?.trim()] || 'Do zrobienia',

    taskId,
    juzMaTask,

    __noData: false
  });
}

console.log(`📊 ${clientMeta.klientNazwa}: ${posts.length} REALNYCH postów`);

if (posts.length === 0) {
  return [{ json: { __noData: true, klientNazwa: clientMeta.klientNazwa } }];
}

return posts.map(p => ({ json: p }));

